sql:
SELECT bin_id, bin_name, bin_quality
FROM genomic_bins
WHERE bin_quality = (SELECT MAX(bin_quality) FROM genomic_bins);

SELECT marker_functional_role 
FROM genomic_bin_markers 
WHERE bin_id = 1;

SELECT bin_id
FROM genomic_bin_quality_control
WHERE qc_result = 'fail';

external_knowledge:
Genomic bins are contiguous segments of DNA that are used to represent a genome; 
The quality score of a genomic bin may be based on various factors such as the assembly quality, completeness, and contamination;
The assembly quality is often measured using metrics like N50 value, which is the median size of contigs in an assembly; 
Marker genes are reference genes used to identify the presence of specific organisms or functional groups in a sample; 
Contamination refers to the presence of non-target organisms or sequences in a sample; 
Quality control is a critical step in ensuring the accuracy and reliability of genomic data; 
Access date refers to the date when a researcher accessed a particular genomic bin;
Researcher refers to an individual who has accessed or worked with the genomic data.

sql:
SELECT bin_id, marker_count, marker_quality
FROM genomic_bin_markers
WHERE marker_quality > 0.9;

SELECT contamination, contamination_method
FROM contamination_metrics
WHERE bin_id = 0;

SELECT bin_name
FROM genomic_bins
WHERE bin_id = 1;

SELECT AVG(contamination_score) AS average_contamination_score
FROM contamination_metrics
WHERE bin_id = 0;

SELECT bin_id, AVG(completeness) as average_completeness
FROM completeness_metrics
GROUP BY bin_id;

SELECT assembly_name, assembly_quality, assembly_coverage
FROM genomic_bin_assemblies
WHERE assembly_quality > 1000000;

SELECT access_id, bin_id, researcher_id, access_date, access_type, access_ip, access_device
FROM genomic_bin_access
WHERE access_type = 'view';

SELECT COUNT(*) AS passed_quality_control_count
FROM genomic_bin_quality_control
WHERE qc_result = 'pass';

SELECT bin_id, MAX(marker_count) AS max_marker_count
FROM genomic_bin_markers
GROUP BY bin_id;
